# Script para descargar dependencias necesarias para Web Scraping\n\n$baseDir = "c:\\Java\\agrocomparador\"\n$libDir = "$baseDir\\lib\"\n\n# Crear carpeta lib si no existe\nif (-Not (Test-Path $libDir)) {\n    New-Item -ItemType Directory -Path $libDir | Out-Null\n    Write-Host \"✓ Carpeta 'lib' creada\" -ForegroundColor Green\n}\n\n# URLs de descarga\n$jsoupUrl = \"https://jsoup.org/dist/jsoup-1.15.3.jar\"\n$jsoupPath = \"$libDir\\jsoup-1.15.3.jar\"\n\nWrite-Host \"\"\nWrite-Host \"╔════════════════════════════════════════════╗\" -ForegroundColor Cyan\nWrite-Host \"║ 📥 Descargando Dependencias                ║\" -ForegroundColor Cyan\nWrite-Host \"╚════════════════════════════════════════════╝\" -ForegroundColor Cyan\nWrite-Host \"\"\n\n# Descargar Jsoup\nif (-Not (Test-Path $jsoupPath)) {\n    Write-Host \"📦 Descargando Jsoup 1.15.3...\" -ForegroundColor Yellow\n    \n    try {\n        $ProgressPreference = 'SilentlyContinue'\n        Invoke-WebRequest -Uri $jsoupUrl -OutFile $jsoupPath\n        \n        if (Test-Path $jsoupPath) {\n            $size = (Get-Item $jsoupPath).Length / 1MB\n            Write-Host \"   ✓ Jsoup descargado ($([math]::Round($size, 2)) MB)\" -ForegroundColor Green\n        }\n    } catch {\n        Write-Host \"   ❌ Error descargando Jsoup\" -ForegroundColor Red\n        Write-Host \"   Intenta descargar manualmente desde: $jsoupUrl\" -ForegroundColor Yellow\n    }\n} else {\n    $size = (Get-Item $jsoupPath).Length / 1MB\n    Write-Host \"   ✓ Jsoup ya existe ($([math]::Round($size, 2)) MB)\" -ForegroundColor Green\n}\n\n# Verificar MySQL Connector\n$mysqlJars = @(\n    \"$libDir\\mysql-connector-java-8.0.33.jar\",\n    \"$libDir\\mysql-connector-j-8.0.33.jar\",\n    \"$libDir\\mysql-connector-java-5.1.49.jar\"\n)\n\n$mysqlFound = $false\nforeach ($jar in $mysqlJars) {\n    if (Test-Path $jar) {\n        $mysqlFound = $true\n        $size = (Get-Item $jar).Length / 1MB\n        Write-Host \"   ✓ MySQL Connector encontrado ($([math]::Round($size, 2)) MB)\" -ForegroundColor Green\n        break\n    }\n}\n\nif (-Not $mysqlFound) {\n    Write-Host \"   ⚠️ MySQL Connector no encontrado\" -ForegroundColor Yellow\n    Write-Host \"   Descargalo desde: https://dev.mysql.com/downloads/connector/j/\" -ForegroundColor Yellow\n    Write-Host \"   Y colócalo en: $libDir\" -ForegroundColor Yellow\n}\n\n# Verificar otros JARs\nWrite-Host \"\"\nWrite-Host \"📂 JARs disponibles en lib/:\" -ForegroundColor Cyan\n\nif (Test-Path $libDir) {\n    $jars = Get-ChildItem -Path $libDir -Filter \"*.jar\"\n    if ($jars) {\n        foreach ($jar in $jars) {\n            $size = $jar.Length / 1MB\n            Write-Host \"   • $($jar.Name) ($([math]::Round($size, 2)) MB)\" -ForegroundColor Green\n        }\n    } else {\n        Write-Host \"   (vacío)\" -ForegroundColor Gray\n    }\n}\n\nWrite-Host \"\"\nWrite-Host \"✅ Configuración completada\" -ForegroundColor Green\nWrite-Host \"\"\nWrite-Host \"Próximos pasos:\" -ForegroundColor Cyan\nWrite-Host \"  1. Crear tabla en BD:\" -ForegroundColor White\nWrite-Host \"     mysql -u root -p agrocomparador < backups/crear_tabla_scraper.sql\" -ForegroundColor Gray\nWrite-Host \"\"\nWrite-Host \"  2. Compilar:\" -ForegroundColor White\nWrite-Host \"     .\\scripts\\build\\compile-with-scraper.bat\" -ForegroundColor Gray\nWrite-Host \"\"\nWrite-Host \"  3. Ejecutar:\" -ForegroundColor White\nWrite-Host \"     java -cp \\\"lib\\*.jar;.\\\" agrocomparador\" -ForegroundColor Gray\nWrite-Host \"\"\n